import safetensors.torch

# Check linear_attn weights stayed BF16
t = safetensors.torch.load_file('/app/fp8_model/model.safetensors-00009-of-00011.safetensors', device='cpu')
for name in sorted(t.keys()):
    if 'layers.0.linear_attn' in name:
        print(f'{name}: dtype={t[name].dtype}, shape={t[name].shape}')

# Check self_attn is quantized
t2 = safetensors.torch.load_file('/app/fp8_model/model.safetensors-00008-of-00011.safetensors', device='cpu')
for name in sorted(t2.keys()):
    if 'layers.11.self_attn' in name:
        print(f'{name}: dtype={t2[name].dtype}, shape={t2[name].shape}')
"

